   340→  function stripMarkdown(text) {
   341→    return text
   342→      .replace(/```[\w]*\n?([\s\S]*?)```/g, '$1')
   343→      .replace(/`([^`]+)`/g, '$1')
   344→      .replace(/^#{1,6}\s+/gm, '')
   345→      .replace(/\*{1,3}([^*\n]+)\*{1,3}/g, '$1')
   346→      .replace(/_{1,3}([^_\n]+)_{1,3}/g, '$1')
   347→      .replace(/~~([^~]+)~~/g, '$1')
   348→      .replace(/!\[([^\]]*)\]\([^)]+\)/g, '')
   349→      .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
   350→      .replace(/^>\s+/gm, '')
