   352→      .replace(/^\|[-| :]+\|$/gm, '')
   353→      .replace(/^\|(.+)\|$/gm, (_, cells) =>
   354→        cells.split('|').map(c => c.trim()).filter(Boolean).join('  '))
   355→      .replace(/\n{3,}/g, '\n\n')
   356→      .trim();
